import{bQ as e,aL as a,u as o,G as d}from"./chunks/framework.D06dwy5q.js";const h=JSON.parse('{"title":"PromQL","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/07-PromQL.md","filePath":"12.可观测性与监控告警/07-PromQL.md","lastUpdated":null}'),s={name:"12.可观测性与监控告警/07-PromQL.md"};function n(p,t,r,c,i,l){return a(),o("div",null,[...t[0]||(t[0]=[d(`<h1 id="promql" tabindex="-1">PromQL <a class="header-anchor" href="#promql" aria-label="Permalink to &quot;PromQL&quot;">​</a></h1><p>Prometheus 把指标存进 TSDB 之后，PromQL 负责从这些时序数据里筛选、计算、聚合和对比。Prometheus 的 Query 页面、Grafana 面板、告警规则，最终都落到 PromQL 表达式上。</p><p>写 PromQL 时最容易卡住的不是语法本身，是指标类型没认清（Counter 不能直接当当前值用）、标签维度没想好（聚合丢掉 instance 后没法定位机器）、时间范围没搞清楚（Instant Vector 和 Range Vector 什么时候用）。</p><h2 id="时间序列-指标名-标签-唯一序列" tabindex="-1">时间序列：指标名 + 标签 = 唯一序列 <a class="header-anchor" href="#时间序列-指标名-标签-唯一序列" aria-label="Permalink to &quot;时间序列：指标名 + 标签 = 唯一序列&quot;">​</a></h2><p>TSDB 里每一条时间序列由&quot;指标名 + 一组标签&quot;唯一确定：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>up{job=&quot;node&quot;, instance=&quot;192.168.10.11:9100&quot;, hostname=&quot;mon01&quot;} 1</span></span>
<span class="line"><span>up{job=&quot;node&quot;, instance=&quot;192.168.10.12:9100&quot;, hostname=&quot;db01&quot;} 1</span></span>
<span class="line"><span>up{job=&quot;node&quot;, instance=&quot;192.168.10.13:9100&quot;, hostname=&quot;cache01&quot;} 1</span></span></code></pre></div><p>指标名都是 <code>up</code>，但 <code>instance</code> 和 <code>hostname</code> 不同，所以是三条不同的序列。给查询加了标签过滤条件后，就只在匹配到的序列里计算。</p><p>标签过滤写在 <code>{}</code> 里：</p><table tabindex="0"><thead><tr><th>写法</th><th>含义</th></tr></thead><tbody><tr><td><code>up</code></td><td>查询所有 <code>up</code> 序列</td></tr><tr><td><code>up{job=&quot;node&quot;}</code></td><td>只查 <code>job</code> 为 <code>node</code> 的</td></tr><tr><td><code>up{job!=&quot;node&quot;}</code></td><td>排除 <code>job</code> 为 <code>node</code> 的</td></tr><tr><td><code>up{hostname=~&quot;db.*&quot;}</code></td><td><code>=~</code> 是正则匹配</td></tr><tr><td><code>up{hostname!~&quot;db.*&quot;}</code></td><td><code>!~</code> 是正则排除</td></tr></tbody></table><h2 id="instant-vector-和-range-vector" tabindex="-1">Instant Vector 和 Range Vector <a class="header-anchor" href="#instant-vector-和-range-vector" aria-label="Permalink to &quot;Instant Vector 和 Range Vector&quot;">​</a></h2><p>这两个概念贯穿所有 PromQL 查询。Instant Vector 是一个时间点上的一组序列及其值：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>up{job=&quot;node&quot;}          # &quot;现在&quot;这个时间点，三台机器的 up 值分别是多少</span></span></code></pre></div><p>Range Vector 是一段时间内的一组序列样本：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_cpu_seconds_total{job=&quot;node&quot;,mode=&quot;idle&quot;}[5m]</span></span>
<span class="line"><span># 最近 5 分钟内，每个时间点的 idle CPU 累计秒数</span></span></code></pre></div><p>两者的差异可以用时间轴看：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20t1%5B%2210%3A00%3Cbr%2F%3E%E6%A0%B7%E6%9C%AC%22%5D%20--%3E%20t2%5B%2210%3A01%3Cbr%2F%3E%E6%A0%B7%E6%9C%AC%22%5D%0A%20%20%20%20t2%20--%3E%20t3%5B%2210%3A02%3Cbr%2F%3E%E6%A0%B7%E6%9C%AC%22%5D%0A%20%20%20%20t3%20--%3E%20t4%5B%2210%3A03%3Cbr%2F%3E%E6%A0%B7%E6%9C%AC%22%5D%0A%20%20%20%20t4%20--%3E%20t5%5B%2210%3A04%3Cbr%2F%3E%E6%A0%B7%E6%9C%AC%22%5D%0A%20%20%20%20t5%20--%3E%20now%5B%2210%3A05%3Cbr%2F%3E%E5%BD%93%E5%89%8D%E6%9F%A5%E8%AF%A2%E7%82%B9%22%5D%0A%0A%20%20%20%20instant%5B%22Instant%20Vector%3Cbr%2F%3E%E5%8F%AA%E5%8F%96%2010%3A05%20%E8%BF%99%E4%B8%AA%E7%82%B9%E7%9A%84%E5%80%BC%22%5D%20-.-%3E%20now%0A%20%20%20%20range%5B%22Range%20Vector%3Cbr%2F%3E%E5%8F%96%2010%3A00%20-%2010%3A05%20%E8%BF%99%E4%B8%80%E6%AE%B5%E6%A0%B7%E6%9C%AC%22%5D%20-.-%3E%20t1%0A%20%20%20%20range%20-.-%3E%20t2%0A%20%20%20%20range%20-.-%3E%20t3%0A%20%20%20%20range%20-.-%3E%20t4%0A%20%20%20%20range%20-.-%3E%20t5%0A%20%20%20%20range%20-.-%3E%20now%0A"></div><p><code>[5m]</code> 把 Instant Vector 变成 Range Vector。<code>rate()</code>、<code>increase()</code>、<code>avg_over_time()</code> 这些函数只能处理 Range Vector——它们需要一段时间内的多个样本才能计算。</p><table tabindex="0"><thead><tr><th>表达式</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>up</code></td><td>Instant Vector</td><td>当前查询时间点的值</td></tr><tr><td><code>up[5m]</code></td><td>Range Vector</td><td>最近 5 分钟内的所有样本点</td></tr><tr><td><code>rate(http_requests_total[5m])</code></td><td>Instant Vector</td><td>输入 Range Vector，根据样本增长算出每秒速率，输出还是 Instant Vector</td></tr></tbody></table><p>Prometheus 页面的 Graph 模式按时间范围连续计算表达式，图上看到的曲线是很多个 Instant Vector 拼起来的；Table 模式只看当前时间点的值和标签。</p><h2 id="counter-算速率-不直接看当前值" tabindex="-1">Counter：算速率，不直接看当前值 <a class="header-anchor" href="#counter-算速率-不直接看当前值" aria-label="Permalink to &quot;Counter：算速率，不直接看当前值&quot;">​</a></h2><p>Counter 只增不减（进程重启会归零）。请求总数、网卡累计字节数、CPU 累计运行秒数——都是 Counter。直接画 Counter 只会看到一条不断往上的线，排查流量和 CPU 时更想知道&quot;每秒变化多少&quot;：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rate(node_network_receive_bytes_total{job=&quot;node&quot;,device!~&quot;lo|veth.*&quot;}[5m])</span></span></code></pre></div><p><code>rate()</code> 取 Range Vector 里的样本，算平均每秒增长速率。Counter 归零时（进程重启），<code>rate()</code> 内部会自动处理——看到当前值比上一个值小，就按重置计算增量，不会算出负速率。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20counter%5B%22Counter%20%E5%8E%9F%E5%A7%8B%E5%BA%8F%E5%88%97%3Cbr%2F%3Ehttp_requests_total%22%5D%20--%3E%20window%5B%22Range%20Vector%3Cbr%2F%3Ehttp_requests_total%5B5m%5D%22%5D%0A%20%20%20%20window%20--%3E%20rate%5B%22rate(...%5B5m%5D)%3Cbr%2F%3E%E8%AE%A1%E7%AE%97%E6%AF%8F%E7%A7%92%E9%80%9F%E7%8E%87%22%5D%0A%20%20%20%20rate%20--%3E%20result%5B%22Instant%20Vector%3Cbr%2F%3E%E5%BD%93%E5%89%8D%E6%9F%A5%E8%AF%A2%E7%82%B9%E7%9A%84%E9%80%9F%E7%8E%87%E7%BB%93%E6%9E%9C%22%5D%0A"></div><p><code>rate()</code> 和 <code>increase()</code> 的区别：<code>rate()</code> 是每秒速率，<code>increase()</code> 是一段时间内的总增量。Grafana 里画图常用 <code>rate()</code>，告警规则里有时用 <code>increase()</code> 判断&quot;过去 N 分钟增加了多少&quot;。</p><h2 id="gauge-直接查当前值" tabindex="-1">Gauge：直接查当前值 <a class="header-anchor" href="#gauge-直接查当前值" aria-label="Permalink to &quot;Gauge：直接查当前值&quot;">​</a></h2><p>Gauge 可增可减，和温度计一样。当前内存、当前连接数、磁盘可用空间——直接查就行：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_memory_MemAvailable_bytes{job=&quot;node&quot;}</span></span>
<span class="line"><span>mysql_global_status_threads_connected</span></span></code></pre></div><p>Gauge 也可以做 <code>avg</code>、<code>max</code>、<code>min</code> 聚合，看整体情况。</p><h2 id="histogram-从桶里算分位数" tabindex="-1">Histogram：从桶里算分位数 <a class="header-anchor" href="#histogram-从桶里算分位数" aria-label="Permalink to &quot;Histogram：从桶里算分位数&quot;">​</a></h2><p>Histogram 用多个桶记录数据分布。比如 HTTP 请求耗时，不是只记一个平均值，而是统计 ≤0.1s 几个、≤0.5s 几个、≤1s 几个……从桶的分布里能算出 P95、P99：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>histogram_quantile(0.95, rate(http_request_duration_seconds_bucket[5m]))</span></span></code></pre></div><p>每个桶本身也是 Counter（只增不减），所以先用 <code>rate()</code> 转成速率，再调 <code>histogram_quantile()</code> 求分位。P95=200ms 和平均值=200ms 含义完全不一样——平均值 200ms 可能是&quot;大部分请求 50ms，偶尔几个 5 秒&quot;的结果，分位数能暴露这个长尾。</p><p>四种类型的查询方式总结：</p><table tabindex="0"><thead><tr><th>类型</th><th>特点</th><th>常见写法</th></tr></thead><tbody><tr><td>Counter</td><td>只增不减，重启归零</td><td><code>rate()</code>、<code>increase()</code></td></tr><tr><td>Gauge</td><td>可增可减</td><td>直接查，或 <code>avg()</code>、<code>max()</code></td></tr><tr><td>Histogram</td><td>分桶记录分布</td><td><code>histogram_quantile()</code> + <code>rate()</code></td></tr><tr><td>Summary</td><td>客户端侧算好分位</td><td>直接查，但跨实例无法重新聚合</td></tr></tbody></table><h2 id="常用主机查询" tabindex="-1">常用主机查询 <a class="header-anchor" href="#常用主机查询" aria-label="Permalink to &quot;常用主机查询&quot;">​</a></h2><p>以下查询使用的指标来自 Node Exporter（部署方式见 <a href="/kb/12.可观测性与监控告警/05-Node Exporter">Node Exporter</a>）。每个指标名对应 Linux 系统的一个观测维度，可以从 Prometheus Query 页面或 Grafana 直接执行。</p><p>按 job 统计成功抓取数量：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sum by (job) (up)</span></span></code></pre></div><p>CPU 使用率——用 100 减去 idle 占比。<code>avg by (instance)</code> 按机器聚合，避免每个 CPU 核心各出一条线。不加 <code>avg by (instance)</code> 时，每台机器的每个 CPU 核心都会画一条独立曲线——8 核机器出 8 条线，面板上几十条线叠在一起，无法辨认是哪台机器的问题：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100 - (</span></span>
<span class="line"><span>  avg by (instance) (</span></span>
<span class="line"><span>    rate(node_cpu_seconds_total{job=&quot;node&quot;,mode=&quot;idle&quot;}[5m])</span></span>
<span class="line"><span>  ) * 100</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>内存使用率——<code>MemAvailable</code> 比 <code>MemFree</code> 更接近&quot;还能分配多少内存&quot;。Linux 会把空闲内存用作 page cache，<code>MemFree</code> 看着低但随时能被回收：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100 * (1 - (</span></span>
<span class="line"><span>  node_memory_MemAvailable_bytes{job=&quot;node&quot;}</span></span>
<span class="line"><span>  /</span></span>
<span class="line"><span>  node_memory_MemTotal_bytes{job=&quot;node&quot;}</span></span>
<span class="line"><span>))</span></span></code></pre></div><p>根分区使用率——<code>fstype!~&quot;tmpfs|overlay&quot;</code> 过滤虚拟文件系统。<code>tmpfs</code> 是内存文件系统，<code>overlay</code> 常见于容器，和真实磁盘容量无关：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>100 * (1 - (</span></span>
<span class="line"><span>  node_filesystem_avail_bytes{job=&quot;node&quot;,mountpoint=&quot;/&quot;,fstype!~&quot;tmpfs|overlay&quot;}</span></span>
<span class="line"><span>  /</span></span>
<span class="line"><span>  node_filesystem_size_bytes{job=&quot;node&quot;,mountpoint=&quot;/&quot;,fstype!~&quot;tmpfs|overlay&quot;}</span></span>
<span class="line"><span>))</span></span></code></pre></div><h2 id="聚合-by-决定保留什么标签" tabindex="-1">聚合：by 决定保留什么标签 <a class="header-anchor" href="#聚合-by-决定保留什么标签" aria-label="Permalink to &quot;聚合：by 决定保留什么标签&quot;">​</a></h2><p><code>by</code> 指定保留哪些标签，其余的被聚合掉。<code>without</code> 反过来——指定去掉哪些标签，其余保留：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>avg by (instance) (rate(node_cpu_seconds_total{job=&quot;node&quot;,mode!=&quot;idle&quot;}[5m]))</span></span>
<span class="line"><span># 结果按 instance 分组，每个 instance 一个值</span></span>
<span class="line"><span></span></span>
<span class="line"><span>count by (job) (up)</span></span>
<span class="line"><span># 按 job 统计数量，instance/hostname 被聚掉了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>up{job=&quot;node&quot;} == 0</span></span>
<span class="line"><span># 直接过滤出抓取失败的实例——没有聚合，保留完整标签用来定位</span></span></code></pre></div><p>聚合维度选择的影响：</p><table tabindex="0"><thead><tr><th>聚合方式</th><th>适合</th><th>失去什么</th></tr></thead><tbody><tr><td><code>sum by (job)</code></td><td>看一类服务整体</td><td>无法定位具体哪台机器</td></tr><tr><td><code>avg by (instance)</code></td><td>看每台机器的平均资源</td><td>丢失 CPU 核心维度</td></tr><tr><td><code>max by (mountpoint)</code></td><td>看每台机器每个挂载点</td><td>告警条数可能翻倍</td></tr><tr><td>不聚合</td><td>排查原始序列</td><td>面板上可能太乱</td></tr></tbody></table><p>告警和看板的聚合取舍不一样。看板可以保留更多维度方便排查；告警规则如果按 <code>instance</code> + <code>mountpoint</code> 出结果，每台机器每个挂载点都可能触一条告警——维度太细时考虑收窄聚合或配合 Alertmanager 做分组。</p><h2 id="验证-promql-的入口" tabindex="-1">验证 PromQL 的入口 <a class="header-anchor" href="#验证-promql-的入口" aria-label="Permalink to &quot;验证 PromQL 的入口&quot;">​</a></h2><p>Prometheus Query 页面适合验证表达式本身：先确认 <code>up{job=&quot;node&quot;}</code> 能返回三台主机，再逐步加函数和聚合。Grafana Explore 用同一条 PromQL 交叉确认数据源和查询结果。</p><table tabindex="0"><thead><tr><th>平台</th><th>路径</th><th>用途</th></tr></thead><tbody><tr><td>Prometheus</td><td><code>Query</code>（中文：查询）</td><td>验证 PromQL 是否有结果</td></tr><tr><td>Prometheus</td><td><code>Status → Target health</code></td><td>看 target 抓取状态</td></tr><tr><td>Grafana</td><td><code>Explore</code>（中文：探索）</td><td>用 Grafana 数据源执行临时查询</td></tr><tr><td>Grafana</td><td><code>Dashboards → 面板菜单 → Edit</code></td><td>检查面板的 PromQL、变量和单位</td></tr></tbody></table><p>Grafana 查不到数据、Prometheus Query 能查到，问题在 Grafana 数据源、时间范围或面板变量。两边都查不到，回到 Targets 页面和指标名确认。</p><h2 id="常见查询问题" tabindex="-1">常见查询问题 <a class="header-anchor" href="#常见查询问题" aria-label="Permalink to &quot;常见查询问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th><th>先看什么</th></tr></thead><tbody><tr><td>查询无结果</td><td>指标名写错、标签不匹配、时间范围没数据</td><td>先查指标名，再逐个加标签条件</td></tr><tr><td>曲线中间断了</td><td>某段时间 target 抓取失败、Prometheus 重启</td><td>查 <code>up</code> 指标和 Targets 页面</td></tr><tr><td>CPU 数值异常高或低</td><td>Counter 直接使用没加 <code>rate()</code>，或聚合维度错了</td><td>用 <code>rate()</code>、明确 <code>by(instance)</code></td></tr><tr><td>磁盘面板出现很多虚拟挂载点</td><td>没过滤 tmpfs、overlay</td><td><code>fstype!~&quot;tmpfs|overlay&quot;</code></td></tr><tr><td>多台机器的数据混成一条线</td><td>聚合丢了 <code>instance</code></td><td>检查 <code>by</code> 和 <code>without</code></td></tr><tr><td>Counter 曲线突然掉到底再涨</td><td>进程重启归零</td><td><code>rate()</code> 自动处理，但突降痕迹还在</td></tr></tbody></table><p>写复杂表达式时，从最简开始一层一层加：原始指标能不能查到 → 加一个标签后还能不能查到 → 套函数后结果对不对 → 聚合后标签维度是不是还够定位。每一步都能确认结果，出了问题也容易知道是哪一步不对。</p>`,58)])])}const b=e(s,[["render",n]]);export{h as __pageData,b as default};
